static void _ariaAppendFile(AriaStr path, AriaStr content) {
    FILE* f = fopen(path.ptr, "a");
    if (!f) { fprintf(stderr, "appendFile failed: %s\n", path.ptr); exit(1); }
    fwrite(content.ptr, 1, content.len, f);
    fclose(f);
}

