/* Generic append dispatch */
#define aria_append_generic(s, elem) _Generic((s), \
    AriaSlice_DeclInfo: aria_append_DeclInfo, \
    AriaSlice_Diagnostic: aria_append_Diagnostic, \
    AriaSlice_Expr: aria_append_Expr, \
    AriaSlice_FieldInfo: aria_append_FieldInfo, \
    AriaSlice_FnSig: aria_append_FnSig, \
    AriaSlice_ImplDef: aria_append_ImplDef, \
    AriaSlice_IrFunc: aria_append_IrFunc, \
    AriaSlice_IrInst: aria_append_IrInst, \
    AriaSlice_Label: aria_append_Label, \
    AriaSlice_MonoSpec: aria_append_MonoSpec, \
    AriaSlice_Scope: aria_append_Scope, \
    AriaSlice_StructDef: aria_append_StructDef, \
    AriaSlice_Suggestion: aria_append_Suggestion, \
    AriaSlice_Symbol: aria_append_Symbol, \
    AriaSlice_Token: aria_append_Token, \
    AriaSlice_TraitDef: aria_append_TraitDef, \
    AriaSlice_TypeInfo: aria_append_TypeInfo, \
    AriaSlice_int64_t: aria_append_int64_t, \
    AriaSlice_AriaStr: aria_append_AriaStr, \
    AriaSlice_double: aria_append_double, \
    AriaSlice_uint8_t: aria_append_uint8_t)(s, elem)

static AriaSlice_DeclInfo aria_slice_from_DeclInfo(int64_t count, ...) {
    AriaSlice_DeclInfo s = {NULL, 0, 0};
    va_list args;
    va_start(args, count);
    for (int64_t i = 0; i < count; i++) {
        s = aria_append_DeclInfo(s, va_arg(args, DeclInfo));
    }
    va_end(args);
    return s;
}

